VALUES
  ('disabled-6f0ba476-moex-00041', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '丙公司X4年1月1日以$2,391,763售出票面金額$2,500,000，五年期，利 率 4％公司債，發行時市場利率 5%，利息於每年 1 月 1 日支付利息一次 。公司債折（溢）價採有效利息法攤銷，假設該公司債券於 X5 年 1 月 1 日於支付利息後，按面額98償還流通在外債券一半，試問X5年1月1日 贖回債券之損益為何？', '["贖回債券利益$19,324", "贖回債券損失$19,324", "贖回債券利益$25,000", "贖回債券損失$25,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00042', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司之普通股核定股本為$4,000,000，每股面額$10。第一次以每股$12 發行150,000股，第二次以每股$10發行100,000股，第三次也發行100,000 股。截至第三次股份發行後，其「資本公積－普通股股票溢價」帳戶餘額 為$500,000。若該公司從未收回股份，試問第三次發行股份時，每股發行 價格是多少？', '["$14", "$13", "$12", "$11"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00043', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司以每股$50出售庫藏股2,000股（面額為$10），若該公司先前購回 庫藏股每股成本為$42，則其帳上的交易記錄應貸記：', '["庫藏股票$84,000及資本公積－股票發行溢價$16,000", "庫藏股票$84,000及資本公積－庫藏股交易$16,000", "庫藏股票$20,000及資本公積－庫藏股交易$80,000", "庫藏股票$20,000及保留盈餘$80,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00044', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司 X4 年度由營業活動產生之現金流量$116,000，當年度應收帳款總 額增加$10,000，存貨減少$3,000，應付帳款增加$5,000，應付公司債折價 攤銷$1,000，預期信用損失$3,500，折舊費用$2,000，則本期淨利為何？', '["$108,000", "$111,500", "$113,500", "$118,500"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00045', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '乙公司為一電器經銷商，該公司提供客戶2年內享有售後免費修理電器服 務，X4 年度銷貨收入為$3,000,000，估計維修費用為銷貨收入的 3%，若 X5年度實際發生修理費用為$75,000，則此時支付維修費用時應記錄：', '["借記維修費用$75,000", "借記維修費用$90,000", "借記產品保證負債準備$75,000", "借記產品保證負債準備$90,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00046', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司X5年度存貨總額增加$10,900，存貨淨額增加$10,400，應付帳款增 加$21,600，若銷貨成本為$904,000，則X5年度支付給供應商款項為何？', '["$892,800", "$893,300", "$915,200", "$936,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00047', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司5月31日銀行對帳單上之存款餘額為$2,512,000，並顯示5月份因 存款不足而退票$32,000，其中有$19,200又於5月底前存入；5月29日銀 行將兌付他公司之支票$28,000 誤自甲公司帳戶中扣除，銀行未發現此錯 誤；5月份銀行代收票據$44,000。若5月底在途存款為$72,000，未兌現支 票為$96,000，則5月31日甲公司帳列之銀行存款餘額為何？', '["$2,459,200", "$2,472,000", "$2,484,800", "$2,491,200"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00048', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司 X5 年 1 月 1 日流通在外普通股為 1,500,000 股，每股面額$50，3 月1 日出售庫藏股 60,000股，4月1 日股票分割1 股分為2 股，8月1日 宣告並發放每股$5 股票股利，11月1 日買回庫藏股 90,000股。若X5 年 甲公司淨利為$9,840,000，宣告普通股股利$1,129,200，特別股股利 $1,152,000，其中 20%為積欠股利，則甲公司 X5 年每股盈餘應為多少？ （四捨五入到小數點後第二位）', '["$2.22", "$2.56", "$2.63", "$2.94"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00049', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司X4年底應收帳款總帳面金額為$8,520,000，備抵損失$476,000。X5 年間沖銷呆帳$342,720，收回 X4 年沖銷呆帳$99,960。若 X5 年底估計應 收帳款的6%無法收回，因此認列預期信用減損損失$337,960，則X5年底 甲公司應收帳款的帳面金額為何？', '["$5,632,665", "$5,931,500", "$8,948,800", "$9,520,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00050', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於X5年初以$819,000購入機器，估計耐用年限6年，殘值$31,500 ，採年數合計法提列折舊，後續衡量採成本模式。X7 年底該機器出現減 損跡象，估計該機器未來現金流量現值為$225,000，公允價值為$240,000， 處分成本為$3,000，X7年底該機器應認列之減損損失金額為何？', '["$31,500", "$19,500", "$9,000", "$0"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
